import org.junit.jupiter.api.Test;

class QueryJoinOptimizerJoinEngineRegionOrderingTest {

	@Test
	void engineReceivesOriginalJoinArgOrder() throws Exception {
		String query = String.join("\n",
				"PREFIX ex: <http://example.com/>",
				"SELECT * WHERE {",
				"  ?s ex:p1 ?o1 .",
				"  ?s ex:p2 ?o2 .",
				"  ?s ex:p3 ?o3 .",
				"}");

		SPARQLParser parser = new SPARQLParser();
		ParsedQuery parsedQuery = parser.parseQuery(query, null);

		AtomicReference<List<TupleExpr>> seenAtoms = new AtomicReference<>();
		CapturingJoinEngine engine = new CapturingJoinEngine(seenAtoms);
		QueryJoinOptimizer optimizer = new QueryJoinOptimizer(new PredicateCardinalityStats(), false,
				new EmptyTripleSource(), true, JoinEngineConfig.defaults(), engine,
				new DefaultUncertaintyAwareEstimator(),
				new ConstantCostModel(), BanditPolicy.noop(), OptimizationTraceSink.NOOP);

		optimizer.optimize(parsedQuery.getTupleExpr(), null, null);

		List<TupleExpr> atoms = seenAtoms.get();
		assertThat(atoms).hasSize(3);
		assertThat(predicates(atoms)).containsExactly("http://example.com/p1", "http://example.com/p2",
				"http://example.com/p3");
	}

	private List<String> predicates(List<TupleExpr> atoms) {
		List<String> values = new ArrayList<>(atoms.size());
		for (TupleExpr atom : atoms) {
			assertThat(atom).isInstanceOf(StatementPattern.class);
			StatementPattern pattern = (StatementPattern) atom;
			assertThat(pattern.getPredicateVar().hasValue()).isTrue();
			values.add(pattern.getPredicateVar().getValue().stringValue());
		}
		return values;
	}

	private static final class CapturingJoinEngine implements JoinOptimizationEngine {

		private final AtomicReference<List<TupleExpr>> seenAtoms;

		private CapturingJoinEngine(AtomicReference<List<TupleExpr>> seenAtoms) {
			this.seenAtoms = seenAtoms;
		}

		@Override
		public OptimizationResult optimizeJoin(Join join, JoinRegion region, JoinOptimizationContext ctx) {
			seenAtoms.set(List.copyOf(region.getAtoms()));
			return new OptimizationResult(join, new PlanDescriptor("test", "capture", "capture"),
					new UncertaintySummary(0.0d));
		}
	}

	private static final class PredicateCardinalityStats extends EvaluationStatistics {

		private final IRI p1 = iri("http://example.com/p1");
		private final IRI p2 = iri("http://example.com/p2");
		private final IRI p3 = iri("http://example.com/p3");

		@Override
		public double getCardinality(TupleExpr expr) {
			if (expr instanceof StatementPattern) {
				StatementPattern pattern = (StatementPattern) expr;
				if (pattern.getPredicateVar() != null && pattern.getPredicateVar().hasValue()) {
					IRI predicate = (IRI) pattern.getPredicateVar().getValue();
					if (p1.equals(predicate)) {
						return 1000.0d;
					}
					if (p2.equals(predicate)) {
						return 1.0d;
					}
					if (p3.equals(predicate)) {
						return 2.0d;
					}
				}
			}
			return super.getCardinality(expr);
		}

		private static IRI iri(String value) {
			return SimpleValueFactory.getInstance().createIRI(value);
		}
	}

	private static final class ConstantCostModel implements CostModel {
		@Override
		public Cost cost(TupleExpr joinTree, JoinOptimizationContext ctx) {
			return new Cost(1.0d, 0.0d, 1.0d, 1.0d);
		}
	}
}
